class CliTests(unittest.TestCase):
    def setUp(self) -> None:
        self._ambient_meta_feedback_enable = os.environ.pop("MYLITTLEHARNESS_META_FEEDBACK_ENABLE", None)
        self._ambient_meta_feedback_root = os.environ.pop("MYLITTLEHARNESS_META_FEEDBACK_ROOT", None)
        self._ambient_meta_feedback_ci_enable = os.environ.pop("MYLITTLEHARNESS_META_FEEDBACK_ENABLE_CI", None)
        os.environ["MYLITTLEHARNESS_META_FEEDBACK_ENABLE"] = "1"

    def tearDown(self) -> None:
        if self._ambient_meta_feedback_enable is None:
            os.environ.pop("MYLITTLEHARNESS_META_FEEDBACK_ENABLE", None)
        else:
            os.environ["MYLITTLEHARNESS_META_FEEDBACK_ENABLE"] = self._ambient_meta_feedback_enable
        if self._ambient_meta_feedback_root is None:
            os.environ.pop("MYLITTLEHARNESS_META_FEEDBACK_ROOT", None)
        else:
            os.environ["MYLITTLEHARNESS_META_FEEDBACK_ROOT"] = self._ambient_meta_feedback_root
        if self._ambient_meta_feedback_ci_enable is None:
            os.environ.pop("MYLITTLEHARNESS_META_FEEDBACK_ENABLE_CI", None)
        else:
            os.environ["MYLITTLEHARNESS_META_FEEDBACK_ENABLE_CI"] = self._ambient_meta_feedback_ci_enable

    def test_phase_owned_file_transaction_calls_pass_explicit_root(self) -> None:
        callsite_files = (
            ROOT / "src/mylittleharness/claims.py",
            ROOT / "src/mylittleharness/planning.py",
            ROOT / "src/mylittleharness/roadmap.py",
            ROOT / "src/mylittleharness/writeback.py",
        )
        missing: list[str] = []
        for path in callsite_files:
            tree = ast.parse(path.read_text(encoding="utf-8"), filename=str(path))
            for node in ast.walk(tree):
                if isinstance(node, ast.Call) and isinstance(node.func, ast.Name) and node.func.id == "apply_file_transaction":
                    if "root" not in {keyword.arg for keyword in node.keywords}:
                        rel_path = path.relative_to(ROOT).as_posix()
                        missing.append(f"{rel_path}:{node.lineno}")
        self.assertEqual([], missing)

    def test_file_transaction_refuses_parent_traversal_outside_explicit_root_before_writes(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp) / "root"
            root.mkdir()
            target = root / ".." / "escaped.txt"
            tmp_path = root / ".escaped.tmp"
            backup_path = root / ".escaped.backup"

            with self.assertRaisesRegex(atomic_files.FileTransactionError, "outside transaction root"):
                atomic_files.apply_file_transaction(
                    (atomic_files.AtomicFileWrite(target, tmp_path, "escaped\n", backup_path),),
                    root=root,
                )

            self.assertFalse((Path(tmp) / "escaped.txt").exists())
            self.assertFalse(tmp_path.exists())
            self.assertFalse(backup_path.exists())

    def test_file_transaction_refuses_symlink_parent_inside_explicit_root_before_writes(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp) / "root"
            outside = Path(tmp) / "outside"
            root.mkdir()
            outside.mkdir()
            link = root / "linked"
            try:
                os.symlink(outside, link, target_is_directory=True)
            except (NotImplementedError, OSError) as exc:
                self.skipTest(f"directory symlinks are unavailable: {exc}")
            target = link / "escaped.txt"
            tmp_path = link / ".escaped.tmp"
            backup_path = link / ".escaped.backup"

            with self.assertRaisesRegex(atomic_files.FileTransactionError, "symlink"):
                atomic_files.apply_file_transaction(
                    (atomic_files.AtomicFileWrite(target, tmp_path, "escaped\n", backup_path),),
                    root=root,
                )

            self.assertFalse((outside / "escaped.txt").exists())
            self.assertFalse((outside / ".escaped.tmp").exists())
            self.assertFalse((outside / ".escaped.backup").exists())

    def test_file_transaction_writes_paths_inside_explicit_root(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp) / "root"
            target = root / "project" / "project-state.md"
            tmp_path = target.with_name(f".{target.name}.tmp")
            backup_path = target.with_name(f".{target.name}.backup")

            cleanup_warnings = atomic_files.apply_file_transaction(
                (atomic_files.AtomicFileWrite(target, tmp_path, "state\n", backup_path),),
                root=root,
            )

            self.assertEqual((), cleanup_warnings)
            self.assertEqual("state\n", target.read_text(encoding="utf-8"))
            self.assertFalse(tmp_path.exists())
            self.assertFalse(backup_path.exists())

    def test_file_transaction_retries_transient_replace_permission_errors(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp) / "root"
            root.mkdir()
            source = root / ".state.tmp"
            target = root / "state.md"
            source.write_text("state\n", encoding="utf-8")
            attempts = {"count": 0}

            def flaky_replace_once(source_path: Path, target_path: Path) -> None:
                attempts["count"] += 1
                if attempts["count"] < 3:
                    raise PermissionError("temporary access denied")
                source_path.replace(target_path)

            with (
                patch.object(atomic_files, "_replace_path_once", side_effect=flaky_replace_once),
                patch.object(atomic_files.time, "sleep") as sleep,
            ):
                atomic_files._replace_path(source, target)

            self.assertEqual(3, attempts["count"])
            self.assertEqual(2, sleep.call_count)
            self.assertFalse(source.exists())
            self.assertEqual("state\n", target.read_text(encoding="utf-8"))

    def test_file_transaction_uses_portable_sidecars_for_dot_prefixed_paths(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp) / "root"
            root.mkdir()
            target = root / "state.md"
            target.write_text("old\n", encoding="utf-8")
            tmp_path = root / ".state.md.tmp"
            backup_path = root / ".state.md.backup"
            calls: list[tuple[str, str]] = []
            original_replace_once = atomic_files._replace_path_once

            def recording_replace_once(source_path: Path, target_path: Path) -> None:
                calls.append((source_path.name, target_path.name))
                original_replace_once(source_path, target_path)

            with patch.object(atomic_files, "_replace_path_once", side_effect=recording_replace_once):
                warnings = atomic_files.apply_file_transaction(
                    (atomic_files.AtomicFileWrite(target, tmp_path, "new\n", backup_path),),
                    root=root,
                )

            self.assertEqual((), warnings)
            self.assertEqual("new\n", target.read_text(encoding="utf-8"))
            self.assertEqual([("state.md.tmp", "state.md")], calls)
            self.assertFalse(tmp_path.exists())
            self.assertFalse(backup_path.exists())
            self.assertFalse((root / "state.md.tmp").exists())
            self.assertFalse((root / "state.md.backup").exists())

    def test_file_transaction_falls_back_to_copy_unlink_after_persistent_replace_permission_errors(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp) / "root"
            root.mkdir()
            source = root / "state.md.tmp"
            target = root / "state.md"
            source.write_text("state\n", encoding="utf-8")

            with (
                patch.object(atomic_files, "_replace_path_once", side_effect=PermissionError("replace denied")),
                patch.object(atomic_files.time, "sleep") as sleep,
            ):
                atomic_files._replace_path(source, target)

            self.assertEqual(len(atomic_files._REPLACE_RETRY_DELAYS_SECONDS), sleep.call_count)
            self.assertFalse(source.exists())
            self.assertEqual("state\n", target.read_text(encoding="utf-8"))

    def test_root_boundary_primitives_detect_symlink_and_escape(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp) / "root"
            outside = Path(tmp) / "outside"
            root.mkdir()
            outside.mkdir()
            link = root / "linked"
            try:
                os.symlink(outside, link, target_is_directory=True)
            except (NotImplementedError, OSError) as exc:
                self.skipTest(f"directory symlinks are unavailable: {exc}")

            target = link / "evidence.md"
            violation = source_path_boundary_violation(root, target, label="evidence")

            self.assertIsNotNone(violation)
            self.assertEqual("symlink", violation.code)
            self.assertEqual(link, first_symlink_prefix(root, target))
            self.assertFalse(path_resolves_within_root(root, root / ".." / "outside" / "evidence.md"))

    def test_root_boundary_primitives_reject_windows_aliases_reserved_names_and_hardlinks(self) -> None:
        self.assertEqual("Windows drive-relative path", windows_path_reference_reason("C:project/project-state.md"))
        self.assertIn("Windows drive-relative", root_relative_path_conflict("C:project/project-state.md"))
        self.assertIn("alternate data stream", root_relative_path_conflict("project/project-state.md:ads"))
        self.assertIn("root-relative", root_relative_path_conflict("/project/project-state.md"))
        self.assertIn("reserved Windows device", root_relative_path_conflict("project/CON.md"))
        self.assertIn("reserved Windows device", record_id_conflict("CON"))

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp) / "root"
            root.mkdir()
            source = root / "source.md"
            alias = root / "alias.md"
            source.write_text("# Source\n", encoding="utf-8")
            try:
                os.link(source, alias)
            except (NotImplementedError, OSError) as exc:
                self.skipTest(f"file hardlinks are unavailable: {exc}")

            violation = source_path_boundary_violation(root, source, label="evidence")

            self.assertIsNotNone(violation)
            self.assertEqual("hardlink", violation.code)
            self.assertIn("multiple hardlink aliases", violation.message)

    def test_inventory_refuses_symlinked_state_as_root_authority(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            base = Path(tmp)
